var abs = Assembly.LoadFrom(absPath);
var asm = Assembly.LoadFrom(asmPath);

foreach (var t in abs.GetExportedTypes().Concat(asm.GetExportedTypes()).OrderBy(t => t.FullName))
{
    Console.WriteLine($"\n=== {t.FullName} ===");
    if (t.BaseType != null && t.BaseType != typeof(object))
        Console.WriteLine($"  base: {t.BaseType.FullName}");
    foreach (var iface in t.GetInterfaces())
        Console.WriteLine($"  implements: {iface.Name}");
    foreach (var c in t.GetConstructors())
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  prop {p.Name}: {p.PropertyType.Name}");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  method {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))}) => {m.ReturnType.Name}");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  static {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))}) => {m.ReturnType.Name}");
}
