using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Provides a web search tool that fetches real results from the DuckDuckGo Instant Answer API.
/// Falls back to a simulated response if the network request fails.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;
    private readonly ILogger<WebSearchTool> _logger;

    public WebSearchTool(HttpClient httpClient, ILogger<WebSearchTool> logger)
    {
        _httpClient = httpClient;
        _logger = logger;
    }

    [Description("Searches the web for information on a given query and returns relevant results. Use this to gather facts about a research topic.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        _logger.LogInformation("🔍 Searching the web for: {Query}", query);

        try
        {
            var encodedQuery = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetStringAsync(url, cancellationToken);
            var doc = JsonDocument.Parse(response);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract / main answer
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[{abstractSource}] {abstractText}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var relatedTopics))
            {
                foreach (var topic in relatedTopics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        !string.IsNullOrWhiteSpace(text.GetString()))
                    {
                        results.Add($"- {text.GetString()}");
                    }
                }
            }

            if (results.Count == 0)
            {
                results.Add($"No detailed results found for '{query}'. Try refining the search query.");
            }

            var output = $"Search results for '{query}':\n{string.Join("\n", results)}";
            _logger.LogDebug("Search returned {Count} results", results.Count);
            return output;
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            _logger.LogWarning(ex, "Web search failed, returning fallback response");
            return $"Search results for '{query}':\n"
                 + $"- Web search is currently unavailable. The query '{query}' could not be completed.\n"
                 + "- Please try again later or use a different search query.";
        }
    }
}

