arguments.new_str:
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- DI container setup ---
var services = new ServiceCollection();

services.AddLogging(builder => builder
    .AddSimpleConsole(o =>
    {
        o.SingleLine = true;
        o.TimestampFormat = "HH:mm:ss ";
    })
    .SetMinimumLevel(LogLevel.Information));

services.AddSingleton<HttpClient>();
services.AddSingleton<WebSearchTool>();
services.AddSingleton<NoteTool>();

var provider = services.BuildServiceProvider();

var loggerFactory = provider.GetRequiredService<ILoggerFactory>();
var webSearch = provider.GetRequiredService<WebSearchTool>();
var noteTool = provider.GetRequiredService<NoteTool>();

// --- Create the chat client through the MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Build tools from annotated methods ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetAllNotes),
};

// --- Create the agent via Microsoft Agent Framework ---
const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic by:
    1. Searching the web multiple times with varied queries to gather diverse information.
    2. Saving key findings as notes using the note-taking tool.
    3. Reviewing all your notes, then producing a well-structured summary.

    Always search at least 2-3 times with different query angles before summarizing.
    Save a note for each important finding. When done researching, retrieve all notes
    and write a final comprehensive summary.
    """;

var agent = chatClient.AsAIAgent(
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes",
    tools: tools,
    loggerFactory: loggerFactory);

// --- Get the research topic ---
string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "artificial intelligence";
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

// --- Run the agent (session and options are optional on the base AIAgent overload) ---
var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}");

// --- Display results ---
Console.WriteLine("\n" + new string('═', 60));
Console.WriteLine("📄 RESEARCH SUMMARY");
Console.WriteLine(new string('═', 60));
Console.WriteLine(response.Text);
Console.WriteLine(new string('═', 60));

// Show note count
Console.WriteLine($"\n📝 Total notes taken: {noteTool.Notes.Count}");
foreach (var note in noteTool.Notes)
{
    Console.WriteLine($"  • {note.Title}");
}

if (response.Usage is { } usage)
{
    Console.WriteLine($"\n📊 Token usage — Input: {usage.InputTokenCount}, Output: {usage.OutputTokenCount}, Total: {usage.TotalTokenCount}");
}

